                                       + vec2(dx.z,dy.z)*uTexSize.zw*8;
ret.y = tex2d(sampler_fc_main,uv_green).y;
ret.y *= 1 + ret.x*0.1;
ret.y -= 0.004 + clamp01(ret.z)*0.012;

